import { clsx, type ClassValue } from "clsx";
import { twMerge } from "tailwind-merge";

/**
 * Merge Tailwind CSS classes with proper conflict resolution.
 * Combines `clsx` for conditional classes and `tailwind-merge`
 * for deduplication of conflicting Tailwind utilities.
 */
export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

/* ============================================
   RTL – Right-to-Left Support for Arabic
   ============================================ */

/* Base RTL text alignment */
[dir="rtl"] {
  text-align: right;
}

/* LTR overrides inside RTL (e.g. phone numbers, emails) */
[dir="rtl"] [dir="ltr"] {
  text-align: left;
  unicode-bidi: embed;
}

/* Flip directional icons in RTL */
[dir="rtl"] .rtl-flip {
  transform: scaleX(-1);
}

/* Adjust spacing for RTL */
[dir="rtl"] .rtl-space-reverse > * + * {
  margin-right: 0;
  margin-left: 0;
}

/* Scrollbar direction */
[dir="rtl"] ::-webkit-scrollbar {
  direction: rtl;
}

/* Input number spinners */
[dir="rtl"] input[type="number"] {
  direction: ltr;
  text-align: right;
}

/* Force LTR for email/url inputs */
[dir="rtl"] input[type="email"],
[dir="rtl"] input[type="url"] {
  direction: ltr;
  text-align: right;
}

