import { clsx, type ClassValue } from "clsx";
import { twMerge } from "tailwind-merge";

/**
 * Merge Tailwind CSS classes with proper conflict resolution.
 * Combines `clsx` for conditional classes and `tailwind-merge`
 * for deduplication of conflicting Tailwind utilities.
 */
export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

/* ============================================
   RTL – Right-to-Left Support for Arabic
   ============================================ */

/* Base RTL text alignment */
[dir="rtl"] {
  text-align: right;
}

/* LTR overrides inside RTL (e.g. phone numbers, emails) */
[dir="rtl"] [dir="ltr"] {
  text-align: left;
  unicode-bidi: embed;
}

/* Flip directional icons in RTL */
[dir="rtl"] .rtl-flip {
  transform: scaleX(-1);
}

/* Adjust spacing for RTL */
[dir="rtl"] .rtl-space-reverse > * + * {
  margin-right: 0;
  margin-left: 0;
}

/* Scrollbar direction */
[dir="rtl"] ::-webkit-scrollbar {
  direction: rtl;
}

/* Input number spinners */
[dir="rtl"] input[type="number"] {
  direction: ltr;
  text-align: right;
}

/* Force LTR for email/url inputs */
[dir="rtl"] input[type="email"],
[dir="rtl"] input[type="url"] {
  direction: ltr;
  text-align: right;
}

"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";
import { type LucideIcon } from "lucide-react";

import { cn } from "@/lib/utils/cn";
import { Tooltip, TooltipContent, TooltipTrigger } from "@/components/ui/tooltip";
import type { NavItem } from "@/lib/constants/navigation";

/* ============================================
   SidebarItem — Nav link with active state
   ============================================ */

type SidebarItemProps = {
  item: NavItem;
  collapsed?: boolean;
  onClick?: () => void;
};

export function SidebarItem({ item, collapsed = false, onClick }: SidebarItemProps) {
  const pathname = usePathname();
  const Icon = item.icon;
  const isActive = item.href === "/dashboard"
    ? pathname === "/dashboard"
    : pathname.startsWith(item.href);

  const content = (
    <Link
      href={item.href}
      onClick={onClick}
      aria-label={item.label}
      aria-current={isActive ? "page" : undefined}
      className={cn(
        "group relative flex items-center gap-3 rounded-lg px-3 py-2.5 text-sm font-medium transition-all duration-200",
        "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring",
        isActive
          ? "bg-primary/10 text-primary sidebar-active"
          : "text-sidebar-foreground hover:bg-sidebar-accent hover:text-sidebar-accent-foreground",
        collapsed && "justify-center px-2"
      )}
    >
      {/* Active indicator bar */}
      <span className="sidebar-active-indicator" />

      <Icon
        className={cn(
          "h-5 w-5 shrink-0 transition-transform duration-200",
          isActive && "text-primary",
          "group-hover:scale-110"
        )}
      />

      {!collapsed && (
        <span className="truncate transition-opacity duration-200">
          {item.label}
        </span>
      )}
    </Link>
  );

  if (collapsed) {
    return (
      <Tooltip>
        <TooltipTrigger asChild>
          {content}
        </TooltipTrigger>
        <TooltipContent side="left" className="font-medium">
          {item.label}
        </TooltipContent>
      </Tooltip>
    );
  }

  return content;
}

